w0 = 2*PI*cf*sr_inv
c = cos(w0)
s = sin(w0)
alpha = s/(2*Q)

a0_inv = 1/(1 + alpha)
a1 = -a0_inv*2*c
a2 = a0_inv*(1 - alpha)
b0 = a0_inv*(1 + c)/2
b1 = -a0_inv*(1 + c)
b2 = a0_inv*(1 + c)/2

static z1 = 0
static z2 = 0

